async function loadRulesForPath(projectRoot, meta, path) {
  const requestedPath = normalizeRulesPath(path);
  const matchedNodes = Object.entries(meta.nodes)
    .filter(([, node]) => minimatch(requestedPath, normalizeRulesPath(node.scope_glob), { dot: true }))
    .sort((left, right) => {
      const priorityDelta = PRIORITY_ORDER[leftNode.priority] - PRIORITY_ORDER[rightNode.priority];
      return priorityDelta !== 0 ? priorityDelta : leftId.localeCompare(rightId);
    });
  return Promise.all(matchedNodes.map(async ([nodeId, node]) => ({...})));
}

class RingBuffer {
  constructor(private readonly capacity: number) { this.buf = new Array(capacity).fill(undefined); }
  push(event: BufferedEvent): void { this.buf[this.head] = event; this.head = (this.head + 1) % this.capacity; }
  replayFrom(afterId: number): BufferedEvent[] {
    const start = this.count < this.capacity ? 0 : this.head;
    for (let i = 0; i < total; i++) {
      const entry = this.buf[(start + i) % this.capacity];
      if (entry !== undefined && entry.id > afterId) result.push(entry);
    }
  }
}

export class ContextCache {
  private readonly metaSlot = new Map<string, CacheEntry<unknown>>();  // Slot 1: AgentsMeta
  private readonly contextSlot = new Map<string, CacheEntry<unknown>>(); // Slot 2: GetRulesContext
  private readonly auditSlot = new Map<string, AuditCursor>(); // Slot 3: audit offset
  invalidate(reason: InvalidationReason, projectRoot?: string): void {
    if (reason === 'meta_write') { this.metaSlot.delete(projectRoot); return; }
    // 'file_watch' — clear both meta and context
    this.metaSlot.delete(projectRoot); this.contextSlot.delete(projectRoot);
  }
}
